def asn1_length(buf, offset):
    if offset >= len(buf):
        return None
    first = buf[offset]
    if first & 0x80 == 0:
        return 1, first
    num = first & 0x7f
    if num == 0 or num > 4:
        return None
    if offset + 1 + num > len(buf):
        return None
    length = int.from_bytes(buf[offset + 1 : offset + 1 + num], 'big')
    return 1 + num, length

